previewCss:
.darma-loader-darma-custom-455 {color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: var(--loader-secondary-color, #67e8f9);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 65px;
   aspect-ratio: 1;
   position: relative;
}
.darma-loader-darma-custom-455:before, .darma-loader-darma-custom-455:after  {
  content: "";
   position: absolute;
   border-radius: 50px;
   box-shadow: 0 0 0 3px inset currentColor;
   animation: darma-loader-darma-custom-455-l5 2.5s infinite;
}
.darma-loader-darma-custom-455:after  {
  animation-delay: -1.25s;
   border-radius: 0;
}
@keyframes darma-loader-darma-custom-455-l5 {
  0% {inset:0 35px 35px 0 }
12.5% {inset:0 35px 0 0 }
25% {inset:35px 35px 0 0 }
37.5% {inset:35px 0 0 0 }
50% {inset:35px 0 0 35px}
62.5% {inset:0 0 0 35px}
75% {inset:0 0 35px 35px}
87.5% {inset:0 0 35px 0 }
100% {inset:0 35px 35px 0 }
}

